"use client";

import { useEffect, useRef, useState } from "react";
import { io, Socket } from "socket.io-client";
import { scrapeGmail, ScrapeResult } from "@/lib/api";

interface ScrapeResultsProps {
  userId: string;
  onContinue: () => void;
}

type Phase = "searching" | "parsing" | "profiling" | "complete" | "error";

const PHASE_LABELS: Record<Phase, string> = {
  searching: "Searching receipts...",
  parsing: "Parsing purchases...",
  profiling: "Building your style profile...",
  complete: "Done!",
  error: "Something went wrong",
};

const SOCKET_URL = process.env.NEXT_PUBLIC_SOCKET_URL || "http://localhost:8000";

export default function ScrapeResults({ userId, onContinue }: ScrapeResultsProps) {
  const [phase, setPhase] = useState<Phase>("searching");
  const [liveCount, setLiveCount] = useState(0);
  const [liveBrands, setLiveBrands] = useState<string[]>([]);
  const [result, setResult] = useState<ScrapeResult | null>(null);
  const [error, setError] = useState("");
  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    // Connect to Socket.io for live progress
    const socket = io(SOCKET_URL, { transports: ["websocket", "polling"] });
    socketRef.current = socket;

    socket.on("connect", () => {
      socket.emit("join_room", { user_id: userId });
    });

    socket.on("scrape_progress", (data: { purchases_count: number; brands_found: string[]; phase: string }) => {
      setLiveCount(data.purchases_count);
      setLiveBrands(data.brands_found);
      if (data.phase === "parsing") setPhase("parsing");
      if (data.phase === "profiling") setPhase("profiling");
    });

    socket.on("scrape_complete", () => {
      setPhase("complete");
    });

    // Trigger the scrape via HTTP
    scrapeGmail(userId)
      .then((data) => {
        setResult(data);
        setPhase("complete");
      })
      .catch((err) => {
        setError(err.message || "Scrape failed");
        setPhase("error");
      });

    return () => {
      socket.disconnect();
    };
  }, [userId]);

  const brandCount = result ? Object.keys(result.brand_freq).length : liveBrands.length;
  const purchaseCount = result ? result.purchases.length : liveCount;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
      <h2 style={{ fontSize: 22, fontWeight: 700, margin: 0 }}>Your Style DNA</h2>

      {/* Progress steps */}
      <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
        {(["searching", "parsing", "profiling", "complete"] as Phase[]).map((p, i) => {
          const isActive = p === phase;
          const isDone =
            (["searching", "parsing", "profiling", "complete"] as Phase[]).indexOf(phase) > i ||
            phase === "complete";
          return (
            <div
              key={p}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 10,
                opacity: isDone || isActive ? 1 : 0.4,
                fontSize: 14,
              }}
            >
              <span
                style={{
                  width: 24,
                  height: 24,
                  borderRadius: "50%",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 12,
                  fontWeight: 600,
                  background: isDone ? "#10b981" : isActive ? "#5B4FE9" : "#e5e7eb",
                  color: isDone || isActive ? "#fff" : "#9ca3af",
                  flexShrink: 0,
                }}
              >
                {isDone && !isActive ? "\u2713" : i + 1}
              </span>
              <span style={{ fontWeight: isActive ? 600 : 400 }}>
                {PHASE_LABELS[p]}
              </span>
              {isActive && phase !== "complete" && (
                <span style={{ marginLeft: 4, animation: "pulse 1.5s infinite" }}>
                  ...
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* Error state */}
      {phase === "error" && (
        <div style={{ background: "#fef2f2", color: "#b91c1c", padding: "12px 16px", borderRadius: 8, fontSize: 14 }}>
          {error}
        </div>
      )}

      {/* Live counter while loading */}
      {phase !== "complete" && phase !== "error" && liveCount > 0 && (
        <p style={{ color: "#666", fontSize: 14, margin: 0 }}>
          Found {liveCount} purchase{liveCount !== 1 ? "s" : ""} from {liveBrands.length} brand{liveBrands.length !== 1 ? "s" : ""} so far...
        </p>
      )}

      {/* Full results */}
      {result && phase === "complete" && (
        <>
          {/* Summary header */}
          <div
            style={{
              background: "#f0fdf4",
              padding: "12px 16px",
              borderRadius: 8,
              fontSize: 14,
              fontWeight: 600,
              color: "#166534",
            }}
          >
            Found {purchaseCount} purchase{purchaseCount !== 1 ? "s" : ""} from {brandCount} brand{brandCount !== 1 ? "s" : ""}
          </div>

          {/* Purchases table */}
          {result.purchases.length > 0 && (
            <div style={{ overflowX: "auto" }}>
              <table
                style={{
                  width: "100%",
                  borderCollapse: "collapse",
                  fontSize: 13,
                }}
              >
                <thead>
                  <tr style={{ borderBottom: "2px solid #e5e7eb", textAlign: "left" }}>
                    <th style={{ padding: "8px 6px", fontWeight: 600 }}>Brand</th>
                    <th style={{ padding: "8px 6px", fontWeight: 600 }}>Item</th>
                    <th style={{ padding: "8px 6px", fontWeight: 600 }}>Price</th>
                    <th style={{ padding: "8px 6px", fontWeight: 600 }}>Date</th>
                    <th style={{ padding: "8px 6px", fontWeight: 600 }}>Category</th>
                  </tr>
                </thead>
                <tbody>
                  {result.purchases.map((p, i) => (
                    <tr key={i} style={{ borderBottom: "1px solid #f3f4f6" }}>
                      <td style={{ padding: "6px", fontWeight: 500 }}>{p.brand}</td>
                      <td style={{ padding: "6px" }}>{p.item_name}</td>
                      <td style={{ padding: "6px" }}>{p.price != null ? `$${p.price.toFixed(2)}` : "-"}</td>
                      <td style={{ padding: "6px", whiteSpace: "nowrap" }}>{p.date || "-"}</td>
                      <td style={{ padding: "6px" }}>{p.category || "-"}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Brand frequency */}
          {Object.keys(result.brand_freq).length > 0 && (
            <div>
              <h3 style={{ fontSize: 15, fontWeight: 600, margin: "0 0 8px 0" }}>Top Brands</h3>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                {Object.entries(result.brand_freq)
                  .sort(([, a], [, b]) => b - a)
                  .map(([brand, count]) => (
                    <span
                      key={brand}
                      style={{
                        background: "#f3f4f6",
                        padding: "4px 10px",
                        borderRadius: 16,
                        fontSize: 13,
                        fontWeight: 500,
                      }}
                    >
                      {brand}: {count}
                    </span>
                  ))}
              </div>
            </div>
          )}

          {/* Style profile */}
          <div>
            <h3 style={{ fontSize: 15, fontWeight: 600, margin: "0 0 8px 0" }}>Style Profile</h3>

            {/* Price range */}
            <p style={{ fontSize: 13, color: "#666", margin: "0 0 8px 0" }}>
              Price range: ${result.profile.price_range.min.toFixed(0)} &ndash; ${result.profile.price_range.max.toFixed(0)}
              {" "}(avg ${result.profile.price_range.avg.toFixed(0)})
            </p>

            {/* Style tags */}
            {result.profile.style_tags.length > 0 && (
              <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
                {result.profile.style_tags.map((tag) => (
                  <span
                    key={tag}
                    style={{
                      background: "#ede9fe",
                      color: "#5B4FE9",
                      padding: "4px 10px",
                      borderRadius: 16,
                      fontSize: 13,
                      fontWeight: 500,
                    }}
                  >
                    {tag}
                  </span>
                ))}
              </div>
            )}

            {/* Narrative summary */}
            {result.profile.narrative_summary && (
              <p style={{ fontSize: 13, color: "#444", lineHeight: 1.5, margin: 0 }}>
                {result.profile.narrative_summary}
              </p>
            )}
          </div>
        </>
      )}

      {/* Continue button */}
      {phase === "complete" && result && (
        <button
          onClick={onContinue}
          style={{
            padding: "14px 24px",
            fontSize: 16,
            fontWeight: 600,
            color: "#fff",
            background: "#5B4FE9",
            border: "none",
            borderRadius: 8,
            cursor: "pointer",
            width: "100%",
          }}
        >
          Continue
        </button>
      )}

      {/* Retry on error */}
      {phase === "error" && (
        <button
          onClick={() => window.location.reload()}
          style={{
            padding: "14px 24px",
            fontSize: 16,
            fontWeight: 500,
            color: "#666",
            background: "transparent",
            border: "1px solid #ddd",
            borderRadius: 8,
            cursor: "pointer",
            width: "100%",
          }}
        >
          Retry
        </button>
      )}
    </div>
  );
}

